  app.get("/api/inbox/calls/unacknowledged", async (req, res) => {
    try {
      const refresh = String(req.query.refresh ?? "1") !== "0";
      const hours = Math.min(168, Math.max(1, parseInt(String(req.query.hours ?? "48"), 10) || 48));
      let backfill = null;
      if (refresh) {
        try {
          backfill = await backfillQuoMissedCalls({
            hours,
            force: String(req.query.force ?? "") === "1",
          });
        } catch (err: any) {
          console.warn(`[quo-call-backfill] ${err?.message ?? err}`);
          backfill = { ok: false, error: err?.message ?? String(err) };
        }
      }
      const limit = Math.min(100, Math.max(1, parseInt(String(req.query.limit ?? "50"), 10) || 50));
      const calls = await storage.getUnacknowledgedQuoCallEvents(limit);
      return res.json({ calls, count: calls.length, backfill });
    } catch (err: any) {
      return res.status(500).json({ error: "Failed to load missed calls", message: err.message });
    }
  });

  app.post("/api/inbox/calls/backfill", async (req, res) => {
    try {
      const hours = Math.min(168, Math.max(1, parseInt(String(req.body?.hours ?? req.query.hours ?? "48"), 10) || 48));
      const result = await backfillQuoMissedCalls({ hours, force: true });
      const calls = await storage.getUnacknowledgedQuoCallEvents(100);
      return res.json({ ...result, pendingCount: calls.length });
    } catch (err: any) {
      return res.status(500).json({ error: "Failed to backfill missed calls", message: err.message });
    }
  });

  app.get("/api/inbox/calls/conversations/:conversationId", async (req, res) => {
    try {
      const conversationId = req.params.conversationId;
      if (!conversationId) return res.status(400).json({ error: "conversationId required" });
      const calls = await storage.getQuoCallEventsByConversation(conversationId, 50);
      return res.json({ calls });
    } catch (err: any) {
      return res.status(500).json({ error: "Failed to load calls", message: err.message });
    }
  });

  app.post("/api/inbox/calls/:id/acknowledge", async (req, res) => {
    try {
      const id = parseInt(req.params.id, 10);
      if (!Number.isFinite(id)) return res.status(400).json({ error: "Invalid call id" });
      const call = await storage.acknowledgeQuoCallEvent(id);
      if (!call) return res.status(404).json({ error: "Call not found" });
      return res.json({ ok: true, call });
    } catch (err: any) {
      return res.status(500).json({ error: "Failed to clear missed call", message: err.message });
    }
  });

  app.post("/api/inbox/calls/:id/callback", async (req, res) => {
    try {
      const id = parseInt(req.params.id, 10);
      if (!Number.isFinite(id)) return res.status(400).json({ error: "Invalid call id" });

      const said = String(req.body?.said ?? "").trim();
      if (said.length < 2) {
        return res.status(400).json({ error: "Callback summary required" });
      }

      const call = await storage.acknowledgeQuoCallEvent(id);
      if (!call) return res.status(404).json({ error: "Call not found" });

      let note = null;
      if (call.conversationId) {
        const formattedPhone = normalizePhone(call.guestPhone) || call.guestPhone;
        note = await storage.createGuestInboxInternalNote({
          conversationId: call.conversationId,
          reservationId: call.reservationId ?? null,
          guestName: call.guestName ?? null,
          guestPhone: call.guestPhone ?? null,
          note: `Called guest back at ${formattedPhone}. Said: ${said}`,
          source: "missed-call-callback",
          createdBy: String(req.body?.createdBy ?? "agent").trim() || "agent",
        });
      }

      return res.json({ ok: true, call, note });
    } catch (err: any) {
      return res.status(500).json({ error: "Failed to complete callback", message: err.message });
    }
  });

  app.post("/api/inbox/calls/conversations/:conversationId/acknowledge", async (req, res) => {
    try {
      const conversationId = req.params.conversationId;
      if (!conversationId) return res.status(400).json({ error: "conversationId required" });
      const cleared = await storage.acknowledgeQuoCallEventsByConversation(conversationId);
      return res.json({ ok: true, cleared });
    } catch (err: any) {
      return res.status(500).json({ error: "Failed to clear missed calls", message: err.message });
    }
  });

